+            StoreUnAlign(padLocalAddr, (RegTensor<T1>&)zeros, ureg1, padColNum);
+            StoreUnAlignPost(padLocalAddr, ureg1, 0);
+
+            ropeYLocalAddr = ropeYLocalAddr + scaleColNum * 2 + padColNum / 2;
+            scaleLocalAddr = scaleLocalAddr + padColNum;
+        }
+    }
