+                    Maxs(x1, x1, fp8Min, pregLoop);
+                    Mins(x1, x1, fp8Max, pregLoop);
+                    StoreOutputData<T1>(yLocalAddr, x1, pregLoop, jR * VL_FP32 + i * dstCurColNumAlign + ropeNum);
