+                // Tail block: odd loopCount leaves 1 group <= 64 elements
+                for (uint16_t t = 0; t < loopCountReminder; t++) {
+                    uint16_t jT = loopCountFoldTwo * 2;
+                    uint32_t tailRem = quantColNum - jT * VL_FP32;
+                    pregLoop = UpdateMask<float>(tailRem);
