+TEMPLATES_DEF_NO_DEFAULT
+__aicore__ inline void SCFABlockCube<TEMPLATE_ARGS>::CalcS1Coord(RunInfo &runInfo,
+    ConstInfo &constInfo)
+{
+    // 计算s1方向偏移
+    coordInfo[runInfo.taskIdMod3].s1Coord = runInfo.s1oIdx * runInfo.qSNumInOneBlock;
+}
