+{
+    if ASCEND_IS_AIV {
+        this->attentionOutGm.SetGlobalBuffer((__gm__ OUTPUT_T *)attentionOut);
+        if (constInfo.needInit == 1) {
+            InitOutputSingleCore(constInfo);
+        }
+    }
+}
