+TEMPLATES_DEF_NO_DEFAULT
+__aicore__ inline void SCFABlockVec<TEMPLATE_ARGS>::GetExtremeValue(
+    T &negativeScalar)
+{
+    uint32_t tmp1 = NEGATIVE_MIN_VAULE_FP32;
+    negativeScalar = *((float *)&tmp1);
+}
