+
+#if defined(__DAV_C310__)
+    #include "hc_pre_m_k_split_core_arch35.h"
+    #include "hc_pre_m_split_core_arch35.h"
+    #include "hc_pre_base_arch35.h"
+    using namespace HcPreNs;
+#else
+    #include "lib/matmul_intf.h"
